#include<bits/stdc++.h>
using namespace std;
int fa[150010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
int main()
{
    int n,k;
    scanf("%d%d",&n,&k);
    int ans=0;
    for(int i=1;i<=n*3;i++)
    {
        fa[i]=i;
    }
    for(int i=1;i<=k;i++)
    {
        int d,x,y;
        scanf("%d%d%d",&d,&x,&y);
        if(x>n||y>n)
        {
            ans++;
            continue;
        }
        if(d==1)
        {
            if(find(x+n)==find(y)||find(x+n*2)==find(y))
            {
                ans++;
                continue;
            }
            merge(x,y);
            merge(x+n,y+n);
            merge(x+n*2,y+n*2);
        }
        else
        {
            if(x==y||find(x)==find(y)||find(x)==find(y+n*2))
            {
                ans++;
                continue;
            }
            merge(x,y+n);
            merge(x+n*2,y);
            merge(x+n,y+n*2);
        }
    }
    printf("%d",ans);
    return 0;
}
